mapper.update:
WITH UPSERT AS
( UPDATE nia.tb_user


        , PW = #{password}


        , NAME = #{name}


        , PHONE_NUMBER = #{mobile}


        , EMAIL = #{email}


        , AGENCY_NAME = #{agencyName}

    , update_time = NOW()

WHERE ID = #{uid} RETURNING * )
INSERT
INTO nia.tb_user
(
    ID
    , PW
    , LVL 
    , LAST_LOGIN
    , UPDATE_TIME

    , NAME


    , PHONE_NUMBER


    , EMAIL


    , AGENCY_NAME

)
SELECT 
    #{uid}
    , #{password}
    , 1::INT
    , NOW()
    , NOW()

    , #{name}


    , #{mobile}


    , #{email}


    , #{agencyName}

WHERE NOT EXISTS
(SELECT *
FROM UPSERT)
